import{_ as t,o as r,c as a,ae as i}from"./chunks/framework.BeVX27ge.js";const h=JSON.parse('{"title":"Prompt Management","description":"","frontmatter":{},"headers":[],"relativePath":"en/admin-prompts.md","filePath":"en/admin-prompts.md"}'),o={name:"en/admin-prompts.md"};function n(s,e,l,d,c,p){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="prompt-management" tabindex="-1">Prompt Management <a class="header-anchor" href="#prompt-management" aria-label="Permalink to &quot;Prompt Management&quot;">​</a></h1><blockquote><p>Control AI behavior to create the most realistic practice experience.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Prompts are the core instructions driving AI behavior. This feature allows administrators to adjust AI responses, evaluation criteria, and persona generation rules to meet company training goals.</p><blockquote><p>Only available to administrators with Prompt Management permissions.</p></blockquote><h2 id="page-structure" tabindex="-1">Page Structure <a class="header-anchor" href="#page-structure" aria-label="Permalink to &quot;Page Structure&quot;">​</a></h2><ul><li><strong>Title Bar</strong>: Company/Department selection, Version selection, and action buttons.</li><li><strong>Prompt Card List</strong>: Displays all prompts under the current version.</li><li><strong>Edit Panel</strong>: Right-side sliding panel providing the detailed editing interface.</li></ul><hr><h2 id="prompt-card-details" tabindex="-1">Prompt Card Details <a class="header-anchor" href="#prompt-card-details" aria-label="Permalink to &quot;Prompt Card Details&quot;">​</a></h2><p>Each card displays:</p><ul><li><strong>Name</strong>: Unique identifier</li><li><strong>Description</strong>: Brief summary</li><li><strong>Category Tag</strong>: Category (e.g., Character, Judge, System, etc.)</li><li><strong>&quot;In Use&quot; Tag</strong>: Appears if the prompt is currently published</li><li><strong>Edit / Delete</strong>: Action buttons</li></ul><hr><h2 id="editing-prompts" tabindex="-1">Editing Prompts <a class="header-anchor" href="#editing-prompts" aria-label="Permalink to &quot;Editing Prompts&quot;">​</a></h2><p>Click <strong>&quot;Edit&quot;</strong> to open the side panel.</p><h3 id="fields" tabindex="-1">Fields <a class="header-anchor" href="#fields" aria-label="Permalink to &quot;Fields&quot;">​</a></h3><ul><li><strong>Name</strong>: Unique identifier (Required).</li><li><strong>Category</strong>: Dropdown selection.</li><li><strong>Description</strong>: Prompt functionality.</li><li><strong>Content</strong>: Large text editor for the full prompt instructions.</li></ul><h3 id="variable-system" tabindex="-1">Variable System <a class="header-anchor" href="#variable-system" aria-label="Permalink to &quot;Variable System&quot;">​</a></h3><p>Use curly braces <code>{...}</code> to insert dynamic variables. Examples: <code>{question}</code>, <code>{character_detail}</code>, <code>{conversation_history}</code>, <code>{stage_description}</code>.</p><hr><h2 id="version-management" tabindex="-1">Version Management <a class="header-anchor" href="#version-management" aria-label="Permalink to &quot;Version Management&quot;">​</a></h2><p>Allows editing and testing prompts without affecting the live environment.</p><ul><li><strong>Add Version</strong>: Duplicates prompts from the current version into a new one.</li><li><strong>Publish</strong>: Sets the selected version as the active version.</li><li>Note: Only the &quot;Published&quot; version applies to new sessions. Ongoing sessions continue to use the older version.</li></ul><hr><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ol><li><strong>Always create a new version</strong> rather than modifying the active version directly.</li><li><strong>Test thoroughly</strong> before publishing.</li></ol>',25)])])}const u=t(o,[["render",n]]);export{h as __pageData,u as default};
